var compName = $('Build Competitor Queries').first().json.name;
var perplexityData = $('Perplexity Competitor Search').first().json;
var content = perplexityData.choices ? perplexityData.choices[0].message.content : 'No data';
var citations = perplexityData.citations || [];
var changeText = $input.first().json.content ? $input.first().json.content[0].text : '{}';
var changes;
try { changes = JSON.parse(changeText.replace(/```json\n?|```/g, '').trim()); } catch(e) { changes = { changes: [], overall_significance: 'LOW' }; }
var lastCrawlId = $('Load Last Crawl').first().json.id || null;

var crawlDataJson = JSON.stringify({ content: content.substring(0, 5000), citations: citations, timestamp: new Date().toISOString() }).replace(/'/g, "''");
var changesJson = JSON.stringify(changes.changes || []).replace(/'/g, "''");
var changeCount = (changes.changes || []).length;
var significance = (changes.overall_significance || 'LOW').replace(/'/g, "''");
var safeCompName = compName.replace(/'/g, "''");
var lastCrawlSql = lastCrawlId ? lastCrawlId.toString() : 'NULL';

var sql = `INSERT INTO gda_competitor_crawls (competitor_name, crawl_data, changes_detected, change_count, significance, previous_crawl_id) VALUES ('${safeCompName}', '${crawlDataJson}'::jsonb, '${changesJson}'::jsonb, ${changeCount}, '${significance}', ${lastCrawlSql}) RETURNING id, competitor_name, change_count, significance`;

return [{ json: { sql, compName, changeCount, significance } }];

