={{ (function() {
  var result = $input.first().json[0] || $input.first().json;
  var name = result.competitor_name || 'Unknown';
  var changes = result.change_count || 0;
  var sig = result.significance || 'LOW';
  if (changes === 0 || sig === 'NONE') return 'COMPETITOR CRAWL: ' + name + ' - No significant changes detected.';
  return 'COMPETITOR ALERT: ' + name + '\nChanges: ' + changes + '\nSignificance: ' + sig + '\nCheck GDA Command for details.';
})() }}

