const items = $('Store Crawl').all();
var totalChanges = 0;
for (var i = 0; i < items.length; i++) {
  var item = items[i].json[0] || items[i].json;
  totalChanges += (item.change_count || 0);
}
return [{ json: { status: 'complete', competitors_crawled: items.length, total_changes: totalChanges, timestamp: new Date().toISOString() } }];
